class SecureStore(
    context: Context,
    prefsName: String,
    encryptedEnabled: Boolean
) {
    private val prefs: SharedPreferences = createPrefs(context, prefsName, encryptedEnabled)

    private fun createPrefs(context: Context, prefsName: String, encryptedEnabled: Boolean): SharedPreferences {
        if (!encryptedEnabled) {
            return context.getSharedPreferences(prefsName, Context.MODE_PRIVATE)
        }
        return try {
            val masterKey = MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()
            EncryptedSharedPreferences.create(
                context,
                prefsName,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
        } catch (_: Throwable) {
            context.getSharedPreferences(prefsName, Context.MODE_PRIVATE)
        }
    }

    fun putString(key: String, value: String?) {
        prefs.edit().putString(key, value).apply()
    }

    fun getString(key: String, default: String? = null): String? = prefs.getString(key, default)

    fun putLong(key: String, value: Long) {
        prefs.edit().putLong(key, value).apply()
    }

    fun getLong(key: String, default: Long = 0L): Long = prefs.getLong(key, default)

    fun putBoolean(key: String, value: Boolean) {
        prefs.edit().putBoolean(key, value).apply()
    }

    fun getBoolean(key: String, default: Boolean = false): Boolean = prefs.getBoolean(key, default)

    fun remove(key: String) {
        prefs.edit().remove(key).apply()
    }

    fun clear() {
        prefs.edit().clear().apply()
    }

    fun sha256(input: String): String {
        val md = MessageDigest.getInstance("SHA-256")
        val bytes = md.digest(input.toByteArray(Charsets.UTF_8))
        val sb = StringBuilder(bytes.size * 2)
        for (b in bytes) sb.append(((b.toInt() and 0xFF) + 0x100).toString(16).substring(1))
        return sb.toString()
    }
}

class WalletManager(
    private val provider: WalletProvider,
    private val store: SecureStore,
    private val dispatcher: CoroutineDispatcher
) {
    private val scope = CoroutineScope(SupervisorJob() + dispatcher)

    fun shutdown() {
        scope.cancel()
    }

    fun debit(
        amountMinor: Long,
        currency: String,
        metadata: Map<String, String> = emptyMap(),
        callback: (PaymentResult) -> Unit
    ) {
        val idempotencyKey = newIdempotencyKey("debit", amountMinor, currency, metadata)
        scope.launch {
            val res = provider.debit(amountMinor, currency, idempotencyKey, metadata)
            withContext(Dispatchers.Main) { callback(res) }
        }
    }

    fun credit(
        amountMinor: Long,
        currency: String,
        metadata: Map<String, String> = emptyMap(),
        callback: (PaymentResult) -> Unit
    ) {
        val idempotencyKey = newIdempotencyKey("credit", amountMinor, currency, metadata)
        scope.launch {
            val res = provider.credit(amountMinor, currency, idempotencyKey, metadata)
            withContext(Dispatchers.Main) { callback(res) }
        }
    }

    suspend fun getTransaction(id: String): WalletTransaction? = withContext(dispatcher) { provider.getTransaction(id) }

    private fun newIdempotencyKey(
        type: String,
        amountMinor: Long,
        currency: String,
        metadata: Map<String, String>
    ): String {
        val base = buildString {
            append(type).append('|')
            append(amountMinor).append('|')
            append(currency.uppercase()).append('|')
            val sorted = metadata.toSortedMap()
            for ((k, v) in sorted) append(k).append('=').append(v).append('&')
            append('|')
            append(UUID.randomUUID().toString())
        }
        val hashed = store.sha256(base)
        store.putString("wallet_last_idempotency", hashed)
        return hashed
    }
}

