class PlayBillingManager(
    private val context: Context,
    private val store: SecureStore
) : PurchasesUpdatedListener {

    private val mainHandler = Handler(Looper.getMainLooper())
    private val isReady = AtomicBoolean(false)
    private val pendingCallbacks = ConcurrentHashMap<String, (PaymentResult) -> Unit>()
    private val productDetailsCache = ConcurrentHashMap<String, ProductDetails>()
    private val connectInProgress = AtomicBoolean(false)

    private val billingClient: BillingClient = BillingClient.newBuilder(context)
        .setListener(this)
        .enablePendingPurchases()
        .build()

    @MainThread
    fun startConnection(onReady: ((Boolean) -> Unit)? = null) {
        if (isReady.get()) {
            onReady?.invoke(true)
            return
        }
        if (connectInProgress.getAndSet(true)) return

        billingClient.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(result: BillingResult) {
                connectInProgress.set(false)
                val ok = result.responseCode == BillingClient.BillingResponseCode.OK
                isReady.set(ok)
                onReady?.invoke(ok)
                if (ok) {
                    queryActivePurchases()
                }
            }

            override fun onBillingServiceDisconnected() {
                isReady.set(false)
                connectInProgress.set(false)
                scheduleReconnect()
            }
        })
    }

    private fun scheduleReconnect() {
        val delayMs = min(30_000L, 2_000L + (System.currentTimeMillis() % 5_000L))
        mainHandler.postDelayed({ startConnection(null) }, delayMs)
    }

    fun shutdown() {
        try {
            billingClient.endConnection()
        } catch (_: Throwable) {
        }
        isReady.set(false)
        pendingCallbacks.clear()
        productDetailsCache.clear()
    }

    fun isConnected(): Boolean = isReady.get()

    @MainThread
    fun queryProductDetails(
        productIds: List<String>,
        @BillingClient.ProductType productType: String,
        callback: (PaymentResult, List<ProductDetails>) -> Unit
    ) {
        startConnection { ok ->
            if (!ok) {
                callback(PaymentResult.Failure("BILLING_UNAVAILABLE", "Billing not available", recoverable = true), emptyList())
                return@startConnection
            }
            val products = productIds.map {
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId(it)
                    .setProductType(productType)
                    .build()
            }
            val params = QueryProductDetailsParams.newBuilder()
                .setProductList(products)
                .build()

            billingClient.queryProductDetailsAsync(params) { result, detailsList ->
                if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                    for (d in detailsList) productDetailsCache[d.productId] = d
                    callback(PaymentResult.Success("query_${System.currentTimeMillis()}"), detailsList)
                } else {
                    callback(
                        PaymentResult.Failure(
                            code = "BILLING_QUERY_FAILED",
                            message = result.debugMessage,
                            recoverable = result.responseCode == BillingClient.BillingResponseCode.SERVICE_DISCONNECTED
                        ),
                        emptyList()
                    )
                }
            }
        }
    }

    @MainThread
    fun launchPurchaseFlow(
        activity: Activity,
        productDetails: ProductDetails,
        offerToken: String? = null,
        obfuscatedAccountId: String? = null,
        obfuscatedProfileId: String? = null,
        callback: (PaymentResult) -> Unit
    ) {
        startConnection { ok ->
            if (!ok) {
                callback(PaymentResult.Failure("BILLING_UNAVAILABLE", "Billing not available", recoverable = true))
                return@startConnection
            }

            val productParamsBuilder = BillingFlowParams.ProductDetailsParams.newBuilder()
                .setProductDetails(productDetails)

            if (!offerToken.isNullOrBlank()) {
                productParamsBuilder.setOfferToken(offerToken)
            } else {
                val tokens = productDetails.subscriptionOfferDetails?.firstOrNull()?.offerToken
                if (!tokens.isNullOrBlank()) productParamsBuilder.setOfferToken(tokens)
            }

            val flowParamsBuilder = BillingFlowParams.newBuilder()
                .setProductDetailsParamsList(listOf(productParamsBuilder.build()))

            val safeAccount = obfuscatedAccountId?.let { store.sha256(it) }
            val safeProfile = obfuscatedProfileId?.let { store.sha256(it) }

            if (!safeAccount.isNullOrBlank()) flowParamsBuilder.setObfuscatedAccountId(safeAccount)
            if (!safeProfile.isNullOrBlank()) flowParamsBuilder.setObfuscatedProfileId(safeProfile)

            val requestId = "p_${System.currentTimeMillis()}_${productDetails.productId}"
            pendingCallbacks[requestId] = callback
            store.putString("billing_last_request_id", requestId)

            val result = billingClient.launchBillingFlow(activity, flowParamsBuilder.build())
            if (result.responseCode != BillingClient.BillingResponseCode.OK) {
                pendingCallbacks.remove(requestId)
                callback(
                    when (result.responseCode) {
                        BillingClient.BillingResponseCode.USER_CANCELED -> PaymentResult.Cancelled
                        BillingClient.BillingResponseCode.SERVICE_DISCONNECTED -> PaymentResult.Failure("BILLING_DISCONNECTED", result.debugMessage, recoverable = true)
                        BillingClient.BillingResponseCode.BILLING_UNAVAILABLE -> PaymentResult.Failure("BILLING_UNAVAILABLE", result.debugMessage, recoverable = true)
                        else -> PaymentResult.Failure("BILLING_LAUNCH_FAILED", result.debugMessage, recoverable = false)
                    }
                )
            }
        }
    }

    @MainThread
    fun acknowledgeIfNeeded(purchase: Purchase, callback: (PaymentResult) -> Unit) {
        if (purchase.isAcknowledged) {
            callback(PaymentResult.Success(purchase.orderIdOrToken(), mapOf("acknowledged" to true)))
            return
        }
        val params = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()
        billingClient.acknowledgePurchase(params) { result ->
            if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                callback(PaymentResult.Success(purchase.orderIdOrToken(), mapOf("acknowledged" to true)))
            } else {
                callback(PaymentResult.Failure("ACK_FAILED", result.debugMessage, recoverable = true))
            }
        }
    }

    @MainThread
    fun consumeIfNeeded(purchase: Purchase, callback: (PaymentResult) -> Unit) {
        val params = ConsumeParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()
        billingClient.consumeAsync(params) { result, outToken ->
            if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                callback(PaymentResult.Success(purchase.orderIdOrToken(), mapOf("consumedToken" to outToken)))
            } else {
                callback(PaymentResult.Failure("CONSUME_FAILED", result.debugMessage, recoverable = true))
            }
        }
    }

    @MainThread
    fun queryActivePurchases(callback: ((List<Purchase>) -> Unit)? = null) {
        startConnection { ok ->
            if (!ok) {
                callback?.invoke(emptyList())
                return@startConnection
            }
            val inappParams = QueryPurchasesParams.newBuilder()
                .setProductType(BillingClient.ProductType.INAPP)
                .build()
            billingClient.queryPurchasesAsync(inappParams) { _, purchases ->
                callback?.invoke(purchases ?: emptyList())
            }
        }
    }

    override fun onPurchasesUpdated(result: BillingResult, purchases: MutableList<Purchase>?) {
        val requestId = store.getString("billing_last_request_id", null)
        val cb = requestId?.let { pendingCallbacks.remove(it) }

        when (result.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                val list = purchases ?: mutableListOf()
                if (list.isEmpty()) {
                    cb?.invoke(PaymentResult.Failure("EMPTY_PURCHASE", "No purchases returned", recoverable = true))
                    return
                }
                val p = list.first()
                when (p.purchaseState) {
                    Purchase.PurchaseState.PURCHASED -> {
                        cb?.invoke(PaymentResult.Success(p.orderIdOrToken(), mapOf("purchaseTokenHash" to store.sha256(p.purchaseToken))))
                    }
                    Purchase.PurchaseState.PENDING -> {
                        cb?.invoke(PaymentResult.Pending(p.orderIdOrToken(), mapOf("purchaseTokenHash" to store.sha256(p.purchaseToken))))
                    }
                    else -> {
                        cb?.invoke(PaymentResult.Failure("PURCHASE_UNSPECIFIED", "Unspecified purchase state", recoverable = true))
                    }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> cb?.invoke(PaymentResult.Cancelled)
            BillingClient.BillingResponseCode.SERVICE_DISCONNECTED -> cb?.invoke(PaymentResult.Failure("BILLING_DISCONNECTED", result.debugMessage, recoverable = true))
            BillingClient.BillingResponseCode.BILLING_UNAVAILABLE -> cb?.invoke(PaymentResult.Failure("BILLING_UNAVAILABLE", result.debugMessage, recoverable = true))
            BillingClient.BillingResponseCode.ITEM_ALREADY_OWNED -> cb?.invoke(PaymentResult.Failure("ITEM_ALREADY_OWNED", result.debugMessage, recoverable = true))
            BillingClient.BillingResponseCode.ITEM_UNAVAILABLE -> cb?.invoke(PaymentResult.Failure("ITEM_UNAVAILABLE", result.debugMessage, recoverable = false))
            else -> cb?.invoke(PaymentResult.Failure("BILLING_ERROR_${result.responseCode}", result.debugMessage, recoverable = true))
        }
    }

    private fun Purchase.orderIdOrToken(): String {
        val id = this.orderId
        if (!id.isNullOrBlank()) return id
        return "token_${store.sha256(this.purchaseToken).take(24)}"
    }
}

object PaymentCompat {
    fun supportsEncryptedPrefs(): Boolean = Build.VERSION.SDK_INT >= Build.VERSION_CODES.M

    fun safeDeviceInfo(): Map<String, String> {
        val sdk = Build.VERSION.SDK_INT.toString()
        val manufacturer = (Build.MANUFACTURER ?: "unknown").take(64)
        val model = (Build.MODEL ?: "unknown").take(64)
        return mapOf(
            "sdk" to sdk,
            "manufacturer" to manufacturer,
            "model" to model
        )
    }
}